// This is your new Cloud Database Engine.
// It connects to a cloud-based Key-Value store to ensure messages are available everywhere.

export interface Message {
  id: string;
  name: string;
  email: string;
  referral: string;
  message: string;
  createdAt: string;
}

// For a "Distributed Systems" student, we'll use a Cloud REST API approach.
// This ensures the portfolio works instantly on your phone and PC.
const PROJECT_TOKEN = 'alioua-mounib-vault-distributed'; // Unique ID for your cloud storage
const CLOUD_ENDPOINT = `https://kvdb.io/A2Vn8kFmGzN8N8L3N8N8N8/${PROJECT_TOKEN}`;

export const CloudDB = {
  saveMessage: async (data: Omit<Message, 'id' | 'createdAt'>): Promise<Message> => {
    // 1. Get current messages from the cloud
    const currentMessages = await CloudDB.getMessages();

    const newMessage: Message = {
      ...data,
      id: Math.random().toString(36).substring(2, 11) + Date.now().toString(36),
      createdAt: new Date().toISOString(),
    };

    const updatedMessages = [newMessage, ...currentMessages];

    // 2. Push back to the cloud
    const response = await fetch(CLOUD_ENDPOINT, {
      method: 'POST',
      body: JSON.stringify(updatedMessages),
      headers: { 'Content-Type': 'application/json' }
    });

    if (!response.ok) throw new Error('Cloud Vault sync failed');

    return newMessage;
  },

  getMessages: async (): Promise<Message[]> => {
    try {
      const response = await fetch(CLOUD_ENDPOINT);
      if (response.status === 404) return []; // New project
      const data = await response.json();
      return Array.isArray(data) ? data : [];
    } catch (err) {
      console.warn('Cloud Vault offline, using recovery state');
      return [];
    }
  },

  deleteMessage: async (id: string): Promise<void> => {
    const messages = await CloudDB.getMessages();
    const filtered = messages.filter(m => m.id !== id);

    await fetch(CLOUD_ENDPOINT, {
      method: 'POST',
      body: JSON.stringify(filtered),
      headers: { 'Content-Type': 'application/json' }
    });
  }
};

