import { initializeApp } from "firebase/app";
import { 
  getFirestore, 
  collection, 
  addDoc, 
  getDocs, 
  deleteDoc, 
  doc, 
  query, 
  orderBy,
  serverTimestamp,
  Timestamp
} from "firebase/firestore";

// Your web app's Firebase configuration
const firebaseConfig = {
  apiKey: "AIzaSyAlo4o11UmQtBPO4LePLQPmRWHTc3GV07Q",
  authDomain: "portfolio-contacts-eff6c.firebaseapp.com",
  databaseURL: "https://portfolio-contacts-eff6c-default-rtdb.europe-west1.firebasedatabase.app",
  projectId: "portfolio-contacts-eff6c",
  storageBucket: "portfolio-contacts-eff6c.firebasestorage.app",
  messagingSenderId: "741581547579",
  appId: "1:741581547579:web:d111505912e7d41b5cd41e",
  measurementId: "G-QF71XPCBWC"
};

// Initialize Firebase
const app = initializeApp(firebaseConfig);
const db = getFirestore(app);

export interface Message {
  id: string;
  name: string;
  email: string;
  referral: string;
  message: string;
  createdAt: string;
}

export const CloudDB = {
  saveMessage: async (data: Omit<Message, 'id' | 'createdAt'>): Promise<void> => {
    try {
      await addDoc(collection(db, "messages"), {
        ...data,
        createdAt: serverTimestamp(),
      });
    } catch (error) {
      console.error("Firebase save error:", error);
      throw error;
    }
  },

  getMessages: async (): Promise<Message[]> => {
    try {
      const q = query(collection(db, "messages"), orderBy("createdAt", "desc"));
      const querySnapshot = await getDocs(q);

      return querySnapshot.docs.map(doc => {
        const data = doc.data();
        // Convert Firebase Timestamp to ISO string for the UI
        const date = data.createdAt instanceof Timestamp 
          ? data.createdAt.toDate().toISOString() 
          : new Date().toISOString();

        return {
          id: doc.id,
          name: data.name,
          email: data.email,
          referral: data.referral,
          message: data.message,
          createdAt: date
        } as Message;
      });
    } catch (error) {
      console.error("Firebase fetch error:", error);
      return [];
    }
  },

  deleteMessage: async (id: string): Promise<void> => {
    try {
      await deleteDoc(doc(db, "messages", id));
    } catch (error) {
      console.error("Firebase delete error:", error);
      throw error;
    }
  }
};

