            ) : status === 'success' ? (
              <span className="flex items-center gap-2">
                <CheckCircle2 size={18} /> Delivered
              </span>
            ) : status === 'error' ? (
               <span className="flex items-center gap-2">
                <AlertCircle size={18} /> Firestore Error
              </span>
            ) : (
              <span className="flex items-center gap-2">
                <Send size={18} /> {content.btn}
              </span>
            )}
          </LiquidButton>

          {status === 'success' && (
            <motion.p
              initial={{ opacity: 0, y: 10 }}
              animate={{ opacity: 1, y: 0 }}
              className="mt-4 text-brand-400 text-sm font-medium"
            >
              {content.success}
            </motion.p>
          )}
        </div>
      </form>
    </div>
  );
};

