export const CloudDB = {
  saveMessage: async (data: Omit<Message, 'id' | 'createdAt'>): Promise<void> => {
    try {
      const messagesRef = ref(db, 'messages');
      const newMessageRef = push(messagesRef);
      await set(newMessageRef, {
