    e.preventDefault();
    if (password === 'alioua.159') {
      sessionStorage.setItem('admin_auth', 'active');
      setIsAuth(true);
      setError(false);
    } else {
      setError(true);
    }
  };

  const handleLogout = () => {
    sessionStorage.removeItem('admin_auth');
    setIsAuth(false);
    onClose();
